import { Fragment } from "react"
import { Button } from '$lib/components/ui/button';
import * as Separator from '$lib/components/ui/separator';
import * as Tooltip from '$lib/components/ui/tooltip';
import { Slider } from '$lib/components/ui/slider';
import { ScanSearch, Plus, Minus } from 'lucide-react';
import { settingsManager } from '$lib/settings/settingsManager';
import { appState, type StateSelector } from '$lib/core/state/appState';
interface Props {
		expanded: boolean;
	}

export function MagnifierPanel(props: Props) {
  const { expanded } = props
  let settings = $state(settingsManager.getSettings());

  settingsManager.addListener((newSettings) => {
      settings = newSettings;
    });

  let zoom = $derived(settings.view.magnifier?.zoom ?? 2.0);

  let size = $derived(settings.view.magnifier?.size ?? 200);

  function updateMagnifierSettings(changes: Partial<{ zoom: number; size: number }>) {
      const current = settings.view.magnifier ?? { zoom: 2.0, size: 200 };
      const newMagnifier = {
        zoom: current.zoom ?? 2.0,
        size: current.size ?? 200,
        ...changes
      };
      console.log('🔍 [Magnifier] Updating settings:', newMagnifier);
      settingsManager.updateNestedSettings('view', {
        magnifier: newMagnifier
      });
    }

  function handleZoomChange(value: number[]) {
      updateMagnifierSettings({ zoom: value[0] });
    }

  function handleSizeChange(value: number[]) {
      updateMagnifierSettings({ size: value[0] });
    }
  return (
    <Fragment>

{expanded ? (<Fragment>
	<div className="border-border/50 flex flex-wrap items-center justify-center gap-1 border-t pt-1">
		<span className="text-muted-foreground mr-2 flex items-center gap-1 text-xs">
			<ScanSearch className="h-3 w-3"></ScanSearch>
			放大倍率
		</span>
		<div className="bg-muted/60 inline-flex min-w-37.5 items-center gap-2 rounded-full px-3 py-1 shadow-inner">
			<span className="w-8 text-right text-xs">{zoom.toFixed(1)}x</span>
			<Slider type="single" value={[zoom]} min={1.0} max={5.0} step={0.1} className="w-24" onValueChange={handleZoomChange}></Slider>
		</div>

		<Separator.Root orientation="vertical" className="mx-2 h-5"></Separator.Root>

		<span className="text-muted-foreground mr-2 text-xs">镜片大小</span>
		<div className="bg-muted/60 inline-flex min-w-37.5 items-center gap-2 rounded-full px-3 py-1 shadow-inner">
			<span className="w-8 text-right text-xs">{size}px</span>
			<Slider type="single" value={[size]} min={100} max={500} step={10} className="w-24" onValueChange={handleSizeChange}></Slider>
		</div>
	</div>
</Fragment>) : null}</Fragment>
  )
}
